mapper.select:
SELECT * FROM (
    SELECT ID, SHOPCODE, SHOPNAME, SHOPBOSS, FUNDINGLIMIT, FUNDINGRATIO,
           ROW_NUMBER() OVER (ORDER BY ID DESC) AS RN
    FROM LZCUSTOMERINFOR

) WHERE RN > #{offset} AND RN <= #{offset} + #{pageSize}

SELECT ID, SHOPCODE, SHOPNAME, SHOPBOSS, FUNDINGLIMIT, FUNDINGRATIO
FROM LZCUSTOMERINFOR
WHERE ID = #{id}

mapper.insert:
MERGE INTO LZCUSTOMERINFOR target USING (
SELECT #{item.shopCode, jdbcType=VARCHAR} AS shopcode, #{item.shopName, jdbcType=VARCHAR} AS shopname, #{item.shopBoss, jdbcType=VARCHAR} AS shopboss, #{item.fundingLimit, jdbcType=VARCHAR} AS fundinglimit, #{item.fundingRatio, jdbcType=VARCHAR} AS fundingratio FROM dual
) source ON (target.SHOPCODE = source.shopcode) WHEN MATCHED THEN UPDATE SET target.SHOPNAME = source.shopname, target.SHOPBOSS = source.shopboss, target.FUNDINGLIMIT = source.fundinglimit, target.FUNDINGRATIO = source.fundingratio WHEN NOT MATCHED THEN INSERT (SHOPCODE, SHOPNAME, SHOPBOSS, FUNDINGLIMIT, FUNDINGRATIO) VALUES (source.shopcode, source.shopname, source.shopboss, source.fundinglimit, source.fundingratio)
